import { Button } from "../ui/button";
import { useTemplateFieldContext } from "../fields";

export interface ExportManagerProps {
  /** Slot to manage export for (e.g. case id). Required so 3rd party controls can render one per slot. */
  slotId: string;
  /** When 'button', only a "Manage exports" button is shown; click opens the host's export editor pane. When 'full', the full form is shown in the pane. Default 'button'. Mirrors packages/ui. */
  variant?: 'button' | 'full';
  /** When true (e.g. opened in the expanding panel), do not show the collapse/expand row. Mirrors packages/ui. */
  embeddedInPanel?: boolean;
  /** Optional. Slot type label (e.g. "case", "path"). When set on the button, passed with openExportEditor for pane header. Mirrors packages/ui. */
  slotLabel?: string;
  /** Optional. Name for this slot instance (e.g. "Case 1"). string | ReactNode for formatting. 3rd party composes it to match their UI; passed with openExportEditor for pane header. Mirrors packages/ui. */
  slotName?: string | React.ReactNode;
  /** Optional. Placeholder for the export code editor. string | ReactNode for formatting. When set on the button, passed with openExportEditor so the pane has it in context. Mirrors packages/ui. */
  exportPlaceholder?: string | React.ReactNode;
}

/** Stub implementation for dev/Storybook. In the host, the real ExportManager from packages/ui is used. API must match packages/ui so 3rd-party code works in both environments. */
export const ExportManager = ({
  slotId,
  variant = 'button',
  slotLabel: slotLabelProp,
  slotName: slotNameProp,
  exportPlaceholder: exportPlaceholderProp,
}: ExportManagerProps) => {
  const {
    slotLabel: slotLabelContext = 'slot',
    slotName: slotNameContext,
    exportPlaceholder: exportPlaceholderContext,
    onOpenExportEditor,
  } = useTemplateFieldContext();
  const slotLabel = slotLabelProp ?? slotLabelContext;
  const slotName = slotNameProp ?? slotNameContext;
  const exportPlaceholder = exportPlaceholderProp ?? exportPlaceholderContext;

  if (variant === 'button') {
    const payloadSlotLabel = typeof slotLabel === 'string' ? slotLabel : undefined;
    const payloadSlotName = typeof slotName === 'string' ? slotName : undefined;
    const payloadPlaceholder = typeof exportPlaceholder === 'string' ? exportPlaceholder : undefined;
    return (
      <Button
        variant="outline"
        size="sm"
        onClick={() => onOpenExportEditor?.({ mode: 'slot', slotId, slotLabel: payloadSlotLabel, slotName: payloadSlotName, placeholder: payloadPlaceholder })}
      >
        Manage {slotLabel} exports
      </Button>
    );
  }

  return (
    <div className="rounded border p-2 text-sm text-muted-foreground">
      Export form (full UI provided by host when running in flow editor).
    </div>
  );
};

export default ExportManager;