/**
 * Hook to subscribe to the slot enabled and active states by slot id.
 * 
 * When used within a DevProvider, uses the dev context's slot enabled state.
 * When used within a production provider, uses the real store.
 * Returns undefined when not inside any provider.
 */
export function useSlotContext(slotId: string): { active: boolean, enabled: boolean } | undefined {

    const devContext = useContext(DevContext);

    // const [devInferredType, setDevInferredType] = useState<string | undefined>(() =>
    //     devContext?.inferredTypes?.[fieldName]
    // );

    const [activeSlotId, setActiveSlotId] = useState<string | undefined>(undefined);

    // Subscribe to DevProvider updates
    useEffect(() => {
        if (devContext) {
            setActiveSlotId(devContext.activeSlotId ?? undefined);
        }
    }, [devContext, slotId]);

    // if (devContext) {
    //     return devInferredType;
    // }

    return { active: (activeSlotId ?? '') === slotId, enabled: true };
}
